// // File: brace-topia.c // Description: This is a simulation of a city of programer agents with different brace placemenmt prefferences. It makes a square grid and the agents inhabit this grid. They can be happy or unhappy and if they are unhappy. If they are unhappy they move to a new spot, this program tracks this by printing the grid and some other informaiton for each cycle. There is either infinite mode or print mode. Basicaly all of this can be controlled with flags, to learn the flags read the print usage function. // // @author Alex Polo aap5772 // // // // // // // // // // // // // // // // // // // // // // // // // // // // // // // // // #define _DEFAULT_SOURCE #include <stdlib.h> #include <stdio.h> #include <assert.h> #include <unistd.h> #include "brace-topia.h" #include "display.h" #include <getopt.h> // Add this for getopt extern char *optarg; // Declare optarg for use int dim = DEFAULT_DIM; int strength = DEFAULT_STRENGTH; // the minimum amount of happiness int vacancy = DEFAULT_VACANCY; int endline = DEFAULT_ENDLINE; int delay = DEFAULT_DELAY; int cycle_count = DEFAULT_CYCLE_COUNT; double ave_happiness = 1; // by default happy /* * @breif: Shuffles the array * * Description: uses fisher yates shuffle for a given array * * @param: char * agents, the array we shuffle * @param: int size, the size of the array */ void shuffle(char * agents, int size){ for (int i = size - 1; i > 0; i--) { int j = rand() % (i + 1); // get a random index from 0 to i (inclusive) // Swap elements i and j. char temp = agents[i]; agents[i] = agents[j]; agents[j] = temp; } } /* * @breif: Initializes the Grid when defining a grid * * Description: Takes the parameters that arent global and makes a square grid of all the agents all in random shuffled spots * then returns the grid * * @param: int size, dimention of one side of the square grid * @param: int end_percent, uses the percent of endlines and vacancies in unision to decide how many of each agent type goes there * @param: int vacancy_percent, similar as endpercent but with the vacancies * @return: returns a fully initialized grid */ Grid * init_grid(int size, int end_percent, int vacancy_percent){ Grid *grid = malloc(sizeof(Grid)); grid -> dim = size; grid -> cells = malloc(size * sizeof(Agent *)); for(int i = 0; i < size; i++){ //going through the whole grid and initializing the agents grid -> cells[i] = malloc(size * sizeof(Agent)); for(int j = 0; j < size; j++){ grid -> cells[i][j].type = VACANT; grid -> cells[i][j].happy = 1; } } int total_cells = grid->dim * grid->dim; //translating the percents to definite numbers int num_end = (total_cells * end_percent) / 100; int num_vacant = (total_cells * vacancy_percent) / 100; int num_newline = total_cells - num_vacant - num_end; // This bit makes every posible cell into their own array, then we go through this one dimetional array and then shuffles the array char * agents = malloc(total_cells * sizeof(char)); int index = 0; for (int i = 0; i < num_end; i++) { agents[index++] = ENDLINE; } for (int i = 0; i < num_newline; i++) { agents[index++] = NEWLINE; } for (int i = 0; i < num_vacant; i++) { agents[index++] = VACANT; } srand(41); // Default random seed shuffle(agents, total_cells); index = 0; // assigns the arrays to the real grid so its not all vacant for (int i = 0; i < size; i++) { for (int j = 0; j < size; j++) { grid->cells[i][j].type = agents[index++]; grid->cells[i][j].happy = 1; } } free(agents); return grid; } /* * @breif: frees the grid * * Description: goes through every element and frees it before freeing the grid struct * * @param: Grid *grid, the grid to be freed */ void free_grid(Grid *grid){ assert(grid); for (int i = 0; i < grid->dim; i++) { free(grid->cells[i]); } free(grid->cells); free(grid); } /* * @breif: Print function * * Description: prints the grid and then the description as exemplified in the instructions * * @param: const Grid *grid, the grid we are printing * @param: int cycle, cycle isnt global but we need to track it outside of print and so we pass it * @param: int moves, same as cycle */ void 
